upstreamCalls.query:
query PaymentTermsOwnerHydrate($id: ID!) {
  order(id: $id) { id paymentTerms { id } totalOutstandingSet { shopMoney { amount currencyCode } presentmentMoney { amount currencyCode } } currentTotalPriceSet { shopMoney { amount currencyCode } presentmentMoney { amount currencyCode } } totalPriceSet { shopMoney { amount currencyCode } presentmentMoney { amount currencyCode } } }
}

query PaymentTermsOwnerHydrate($id: ID!) {
  draftOrder(id: $id) { id paymentTerms { id } subtotalPriceSet { shopMoney { amount currencyCode } } totalPriceSet { shopMoney { amount currencyCode } } }
}

missingOrder.query:
#graphql
  mutation PaymentTermsReferenceNotFound($referenceId: ID!, $attrs: PaymentTermsCreateInput!) {
    paymentTermsCreate(referenceId: $referenceId, paymentTermsAttributes: $attrs) {
      paymentTerms {
        id
      }
      userErrors {
        field
        message
        code
      }
    }
  }

